function solve(n: number, edges: number[][], label: string): number {
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 1; // At least one node is a palindrome of length 1

    const dfs = (currentNode: number, visited: number, path: number[]): void => {
        // Check if current path is a palindrome
        const len = path.length;
        let isPal = true;
        for (let i = 0; i < Math.floor(len / 2); i++) {
            if (label[path[i]] !== label[path[len - 1 - i]]) {
                isPal = false;
                break;
            }
        }
        if (isPal) {
            maxLen = Math.max(maxLen, len);
        }

        // Try to visit neighbors
        for (const neighbor of adj[currentNode]) {
            if ((visited & (1 << neighbor)) === 0) {
                const newPath = [...path, neighbor];
                dfs(neighbor, visited | (1 << neighbor), newPath);
            }
        }
    };

    for (let i = 0; i < n; i++) {
        dfs(i, 1 << i, [i]);
    }

    return maxLen;
}
